2	import { useTranslation } from 'react-i18next';
3	import { ICON_SIZE, Icons, type LucideLikeIcon } from '@bim-ai/ui';
4	
5	import { TAB_KIND_LABEL, type TabKind, type ViewTab } from './tabsModel';
6	
7	/**
8	 * TabBar — spec §11.3.
9	 *
10	 * Horizontal strip of open-view tabs sitting between the TopBar and
11	 * the canvas. Each tab carries a `kind` icon, a truncated label, and a
12	 * close ✕ button. Trailing `+` opens an "add view" popover.
13	 */
14	
15	const TAB_KIND_ICON: Record<TabKind, LucideLikeIcon> = {
16	  plan: Icons.floor!,
17	  '3d': Icons.family!, // Component (cube) — used for 3D views
18	  'plan-3d': Icons.floor!,
19	  section: Icons.section!,
20	  sheet: Icons.sheet!,
21	  schedule: Icons.schedule!,
22	  agent: Icons.agent!,
23	};
24	
25	export interface TabBarProps {
26	  tabs: ViewTab[];
27	  activeId: string | null;
28	  onActivate: (id: string) => void;
29	  onClose: (id: string) => void;
30	  /** Called when the user clicks a "+ {kind}" entry in the trailing
31	   * popover. The kind names a target the host should resolve (e.g.
32	   * "+ Plan" → open the active level as a tab). */
33	  onAdd?: (kind: TabKind) => void;
34	  /** Called when the user drags a tab to a new position. The host
35	   * should run the `reorderTab` reducer with the same indices. */
36	  onReorder?: (fromIdx: number, toIdx: number) => void;
37	}
38	
39	const ADDABLE_KINDS: TabKind[] = ['plan', '3d', 'plan-3d', 'section', 'sheet', 'schedule', 'agent'];
40	
41	export function TabBar({
42	  tabs,
43	  activeId,
44	  onActivate,
45	  onClose,
46	  onAdd,
47	  onReorder,
48	}: TabBarProps): JSX.Element {
49	  const { t } = useTranslation();
50	  const [popoverOpen, setPopoverOpen] = useState(false);
51	  const [dragSrc, setDragSrc] = useState<number | null>(null);
52	  const [dragOverIdx, setDragOverIdx] = useState<number | null>(null);
53	  const popoverRef = useRef<HTMLDivElement | null>(null);
54	
55	  // Click-outside closes the popover.
56	  useEffect(() => {
57	    if (!popoverOpen) return;
58	    const onDoc = (e: MouseEvent): void => {
59	      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
60	        setPopoverOpen(false);
61	      }
62	    };
63	    document.addEventListener('mousedown', onDoc);
64	    return () => document.removeEventListener('mousedown', onDoc);
65	  }, [popoverOpen]);
66	
67	  return (
68	    <div
69	      role="tablist"
70	      aria-label={t('workspace.openViews')}
71	      data-testid="view-tabs"
72	      className="flex items-end gap-0.5 border-b border-border bg-surface px-2 pt-1.5"
73	      style={{ height: 38 }}
74	    >
75	      {tabs.length === 0 ? (
76	        <div className="px-2 pb-1.5 text-xs text-muted">{t('workspace.noViewsOpen')}</div>
77	      ) : null}
78	      {tabs.map((tab, idx) => {
79	        const Icon = TAB_KIND_ICON[tab.kind] ?? Icons.floor!;
80	        const isActive = tab.id === activeId;
81	        const isDragOver = dragOverIdx === idx && dragSrc !== null && dragSrc !== idx;
82	        const truncated = tab.label.length > 22 ? tab.label.slice(0, 21) + '…' : tab.label;
83	        return (
84	          <div
85	            key={tab.id}
86	            role="tab"
87	            aria-selected={isActive}
88	            data-tab-id={tab.id}
89	            data-tab-index={idx}
90	            data-active={isActive ? 'true' : 'false'}
91	            data-drag-over={isDragOver ? 'true' : 'false'}
92	            draggable={Boolean(onReorder)}
93	            onDragStart={(e) => {
94	              if (!onReorder) return;
95	              setDragSrc(idx);
96	              e.dataTransfer.effectAllowed = 'move';
97	              try {
98	                e.dataTransfer.setData('text/plain', String(idx));
99	              } catch {
100	                /* some browsers throw on setData inside synthetic events */
101	              }
102	            }}
103	            onDragOver={(e) => {
104	              if (!onReorder || dragSrc === null) return;
105	              e.preventDefault();
106	              e.dataTransfer.dropEffect = 'move';
107	              if (dragOverIdx !== idx) setDragOverIdx(idx);
108	            }}
109	            onDragLeave={() => {
110	              if (dragOverIdx === idx) setDragOverIdx(null);
111	            }}
112	            onDrop={(e) => {
113	              if (!onReorder || dragSrc === null) return;
114	              e.preventDefault();
115	              if (dragSrc !== idx) onReorder(dragSrc, idx);
116	              setDragSrc(null);
117	              setDragOverIdx(null);
118	            }}
119	            onDragEnd={() => {
120	              setDragSrc(null);
121	              setDragOverIdx(null);
122	            }}
123	            className={[
124	              'group flex items-center gap-1.5 rounded-t-md border border-b-0 px-3 py-1.5 text-xs font-medium transition-colors',
125	              isActive
126	                ? 'border-border bg-background text-foreground shadow-sm'
127	                : 'border-transparent text-muted hover:bg-background/60 hover:text-foreground',
128	              isDragOver ? 'ring-2 ring-accent ring-offset-0' : '',
129	            ].join(' ')}
130	            style={
131	              isActive
132	                ? { boxShadow: 'inset 0 -2px 0 0 var(--color-accent), 0 -1px 3px 0 rgba(0,0,0,0.04)' }
133	                : undefined
134	            }
135	          >
136	            <button
137	              type="button"
138	              onClick={() => onActivate(tab.id)}
139	              aria-label={`${t(`workspace.tabs.${tab.kind}`)}: ${tab.label}`}
140	              className="flex items-center gap-1.5 rounded"
141	              title={`${t(`workspace.tabs.${tab.kind}`)} · ${tab.label}`}
142	              data-testid={`tab-activate-${tab.id}`}
143	            >
144	              <Icon
145	                size={13}
146	                aria-hidden="true"
147	                className={isActive ? 'text-accent' : 'text-muted'}
148	              />
149	              <span className="whitespace-nowrap">{truncated}</span>
150	            </button>
151	            <button
152	              type="button"
153	              onClick={(e) => {
154	                e.stopPropagation();
155	                onClose(tab.id);
156	              }}
157	              aria-label={t('workspace.closeTab', { label: tab.label })}
158	              data-testid={`tab-close-${tab.id}`}
159	              className={[
160	                'rounded p-0.5 hover:bg-surface-strong',
161	                isActive ? 'opacity-50 hover:opacity-100' : 'opacity-0 group-hover:opacity-50 group-hover:hover:opacity-100',
162	              ].join(' ')}
163	            >
164	              <Icons.close size={11} aria-hidden="true" />
165	            </button>
166	          </div>
167	        );
168	      })}
169	      <div className="relative ml-1 mb-1.5" ref={popoverRef}>
170	        <button
171	          type="button"
172	          onClick={() => setPopoverOpen((v) => !v)}
173	          aria-label={t('workspace.openNewView')}
174	          data-testid="tab-add-button"
175	          className="flex h-6 w-6 items-center justify-center rounded text-muted hover:bg-surface-strong hover:text-foreground"
176	          style={{ fontSize: 16, lineHeight: 1 }}
177	        >
178	          +
179	        </button>
180	        {popoverOpen ? (
181	          <div
182	            role="menu"
183	            data-testid="tab-add-popover"
184	            className="absolute left-0 top-full z-30 mt-1 flex min-w-[180px] flex-col rounded-md border border-border bg-surface shadow-elev-2"
185	          >
186	            {ADDABLE_KINDS.map((kind) => {
187	              const Icon = TAB_KIND_ICON[kind];
188	              return (
189	                <button
190	                  key={kind}
191	                  type="button"
192	                  role="menuitem"
193	                  onClick={() => {
194	                    setPopoverOpen(false);
195	                    onAdd?.(kind);
196	                  }}
197	                  className="flex items-center gap-2 px-3 py-1.5 text-left text-xs text-foreground hover:bg-surface-strong"
198	                  data-testid={`tab-add-${kind}`}
199	                >
200	                  <Icon size={ICON_SIZE.chrome} aria-hidden="true" />
201	                  <span>+ {t(`workspace.tabs.${kind}`)}</span>
202	                </button>
203	              );
204	            })}
205	          </div>
206	        ) : null}
207	      </div>
208	    </div>
209	  );
210	}
